SeasonConfig = {}
SeasonConfig.Gradings = {}

function SeasonConfig:loadConfig()
    local configs = FileUtil.getConfigFromCsv("setting/SeasonSetting.csv", 3)
    for _, config in pairs(configs) do
        local item = {
            id = tonumber(config.Id),
            icon = config.HonorIcon,
            honorId = tonumber(config.HonorId),
            name = config.Name,
            honorName = config.HonorName,
            flag = config.HonorFlag,
            defaultScore = tonumber(config.DefaultScore),
            danIcon = config.DanIcon
        }
        self.Gradings[item.honorId] = item
    end
end

function SeasonConfig:getSeasonSetting()
    return self.Gradings
end

function SeasonConfig:getSeasonByHonorId(id)
    return self.Gradings[tonumber(id)]
end